import React from 'react';
import * as LucideIcons from 'lucide-react';

const iconNames = [
    'Bot', 'MessageSquare', 'Zap', 'Sparkles', 'FileText', 'Workflow', 'Code',
    'PenTool', 'PenLine', 'Keyboard', 'Siren', 'Sun', 'Volume2', 'Thermometer',
    'Users', 'Wrench', 'Eraser', 'Palette', 'Library', 'Video', 'Film', 'Mic',
    'Youtube', 'Monitor', 'Music', 'Headphones', 'Scissors', 'Presentation',
    'Search', 'MonitorPlay', 'Terminal', 'Code2', 'Cpu', 'Layout', 'Cloud',
    'Share2', 'BookOpen', 'Brush', 'Paperclip', 'Beaker', 'Settings', 'Box',
    'Plane', 'Crosshair', 'Puzzle', 'Database', 'Component', 'File', 'Calculator',
    'Atom', 'MessageCircle', 'UserCheck', 'QrCode', 'Download', 'X', 'Circle',
    'Gamepad2', 'Glasses', 'Layers', 'Magnet', 'Ship', 'ArrowUp', 'ArrowDown',
    'ChevronDown', 'ChevronUp', 'Send', 'Lightbulb', 'Eye', 'Moon', 'Globe',
    'Droplets', 'Triangle', 'Scale', 'Shapes', 'Binary', 'Laptop', 'TestTube',
    'BarChart', 'Swords', 'Languages', 'Ghost', 'Hammer', 'Pipette', 'Heart',
    'Image', 'ExternalLink', 'List', 'Grid', 'Link', 'Trash2'
];

const IconComponents = iconNames.reduce((acc, name) => {
    acc[name] = LucideIcons[name] || LucideIcons.Link;
    return acc;
}, {});

IconComponents.SparklesIcon = LucideIcons.Sparkles;

export const LucideIcon = ({ name, className }) => {
    const IconComponent = IconComponents[name] || LucideIcons.Link;
    return <span className={className}><IconComponent /></span>;
};

export default IconComponents;