import React from 'react';
import { LucideIcon } from './IconMap.jsx';

export const ToolCardGrid = ({ tool, onShowQR, isBookmarked, onToggleBookmark, onVisit }) => (
    <div className="group relative bg-white dark:bg-slate-900/80 rounded-xl border border-gray-100 dark:border-slate-800 p-5 flex flex-col h-full card-hover overflow-hidden backdrop-blur-sm">
        <div className="absolute top-0 right-0 w-20 h-20 bg-gradient-to-br from-indigo-50 to-transparent dark:from-cyan-900/30 rounded-bl-full opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>

        <div className="flex justify-between items-start mb-4 relative z-10">
            <div className="p-3 bg-gray-50 dark:bg-slate-800 rounded-lg text-primary dark:text-cyan-400 group-hover:bg-primary group-hover:text-white dark:group-hover:bg-cyan-500 dark:group-hover:text-slate-950 transition-colors duration-300 shadow-sm">
                <LucideIcon name={tool.icon} className="w-6 h-6" />
            </div>
            <button
                onClick={(e) => {
                    e.preventDefault();
                    onToggleBookmark(tool);
                }}
                className={`p-2 rounded-lg transition-all duration-300 ${
                    isBookmarked
                        ? 'text-red-500 hover:text-red-600'
                        : 'text-gray-400 hover:text-red-500'
                }`}
                title={isBookmarked ? "移除書籤" : "加入書籤"}
                aria-label={isBookmarked ? "移除書籤" : "加入書籤"}
                aria-pressed={isBookmarked}
            >
                <LucideIcon name={isBookmarked ? "Heart" : "Heart"} className={`w-5 h-5 ${isBookmarked ? 'fill-current' : ''}`} />
            </button>
        </div>

        <h3 className="text-lg font-bold text-text dark:text-cyan-50 mb-2 group-hover:text-primary dark:group-hover:text-cyan-400 transition-colors relative z-10">
            {tool.name}
        </h3>

        <p className="text-sm text-muted dark:text-slate-400 mb-6 flex-grow leading-relaxed relative z-10">
            {tool.desc}
        </p>

        <div className="mt-auto flex gap-2 relative z-10">
            <a
                href={tool.url}
                target="_blank"
                rel="noopener noreferrer"
                className={`flex-grow flex items-center justify-center py-2.5 bg-gray-50 dark:bg-slate-800 text-text dark:text-slate-200 text-sm font-medium rounded-lg border border-gray-200 dark:border-slate-700 hover:bg-black hover:text-white hover:border-black dark:hover:bg-cyan-600 dark:hover:text-white dark:hover:border-cyan-500 transition-all duration-300 gap-2 ${tool.url === '#' ? 'opacity-50 cursor-not-allowed' : ''}`}
                onClick={(e) => {
                    if (tool.url === '#') {
                        e.preventDefault();
                    } else {
                        onVisit?.(tool);
                    }
                }}
                aria-label={`前往 ${tool.name}`}
            >
                {tool.url === '#' ? '即將推出' : '立即訪問'} <LucideIcon name="ExternalLink" className="w-4 h-4" aria-hidden="true" />
            </a>
            {tool.url !== '#' && (
                <button
                    onClick={() => onShowQR(tool.url, tool.name)}
                    className="flex items-center justify-center w-[46px] bg-gray-50 dark:bg-slate-800 text-gray-600 dark:text-slate-400 rounded-lg border border-gray-200 dark:border-slate-700 hover:bg-indigo-100 hover:text-primary hover:border-indigo-200 dark:hover:bg-cyan-900/30 dark:hover:text-cyan-400 dark:hover:border-cyan-500/50 transition-all duration-300"
                    title="生成 QR Code"
                    aria-label={`為 ${tool.name} 生成 QR Code`}
                >
                    <LucideIcon name="QrCode" className="w-5 h-5" />
                </button>
            )}
        </div>
    </div>
);

export const ToolCardList = ({ tool, onShowQR, isBookmarked, onToggleBookmark, onVisit }) => (
    <div className="tool-list-item group bg-white dark:bg-slate-900/80 rounded-xl border border-gray-100 dark:border-slate-800 p-4 card-hover">
        <div className="flex items-center gap-4">
            <div className="flex-shrink-0">
                <div className="p-3 bg-gray-50 dark:bg-slate-800 rounded-lg text-primary dark:text-cyan-400 group-hover:bg-primary group-hover:text-white dark:group-hover:bg-cyan-500 dark:group-hover:text-slate-950 transition-colors duration-300 shadow-sm">
                    <LucideIcon name={tool.icon} className="w-5 h-5" />
                </div>
            </div>
            <div className="flex-grow min-w-0">
                <h3 className="text-base font-bold text-text dark:text-cyan-50 group-hover:text-primary dark:group-hover:text-cyan-400 transition-colors truncate">
                    {tool.name}
                </h3>
                <p className="text-sm text-muted dark:text-slate-400 leading-relaxed line-clamp-2">
                    {tool.desc}
                </p>
            </div>
            <div className="flex-shrink-0 flex gap-2 items-center">
                <button
                    onClick={() => onToggleBookmark(tool)}
                    className={`p-2 rounded-lg transition-all duration-300 ${
                        isBookmarked
                            ? 'text-red-500 hover:text-red-600'
                            : 'text-gray-400 hover:text-red-500'
                    }`}
                    title={isBookmarked ? "移除書籤" : "加入書籤"}
                    aria-label={isBookmarked ? "移除書籤" : "加入書籤"}
                    aria-pressed={isBookmarked}
                >
                    <LucideIcon name={isBookmarked ? "Heart" : "Heart"} className={`w-5 h-5 ${isBookmarked ? 'fill-current' : ''}`} />
                </button>
                <a
                    href={tool.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className={`px-4 py-2 bg-gray-50 dark:bg-slate-800 text-text dark:text-slate-200 text-sm font-medium rounded-lg border border-gray-200 dark:border-slate-700 hover:bg-primary hover:text-white hover:border-primary dark:hover:bg-cyan-600 dark:hover:text-white dark:hover:border-cyan-500 transition-all duration-300 ${tool.url === '#' ? 'opacity-50 cursor-not-allowed' : ''}`}
                    onClick={(e) => {
                        if (tool.url === '#') {
                            e.preventDefault();
                        } else {
                            onVisit?.(tool);
                        }
                    }}
                    aria-label={`前往 ${tool.name}`}
                >
                    {tool.url === '#' ? '即將推出' : '前往'} <LucideIcon name="ExternalLink" className="w-3 h-3 inline ml-1" aria-hidden="true" />
                </a>
                {tool.url !== '#' && (
                    <button
                        onClick={() => onShowQR(tool.url, tool.name)}
                        className="p-2 bg-gray-50 dark:bg-slate-800 text-gray-600 dark:text-slate-400 rounded-lg border border-gray-200 dark:border-slate-700 hover:bg-indigo-100 hover:text-primary hover:border-indigo-200 dark:hover:bg-cyan-900/30 dark:hover:text-cyan-400 dark:hover:border-cyan-500/50 transition-all duration-300"
                        title="QR Code"
                        aria-label={`為 ${tool.name} 生成 QR Code`}
                    >
                        <LucideIcon name="QrCode" className="w-4 h-4" />
                    </button>
                )}
            </div>
        </div>
    </div>
);

const ToolCard = ({ tool, onShowQR, view = 'grid', isBookmarked, onToggleBookmark, onVisit }) => {
    if (view === 'list') {
        return <ToolCardList tool={tool} onShowQR={onShowQR} isBookmarked={isBookmarked} onToggleBookmark={onToggleBookmark} onVisit={onVisit} />;
    }
    return <ToolCardGrid tool={tool} onShowQR={onShowQR} isBookmarked={isBookmarked} onToggleBookmark={onToggleBookmark} onVisit={onVisit} />;
};

export default ToolCard;