import React from 'react';
import { LucideIcon } from './IconMap.jsx';

const CategoryNav = ({ categories, activeCategory, onCategoryChange, getToolsCount, isCyberMode }) => {
    return (
        <nav 
            id="category-nav" 
            role="navigation" 
            aria-label="分類導航"
            className={`sticky top-0 z-40 backdrop-blur-sm py-4 -mx-6 px-6 md:static md:bg-transparent md:p-0 mb-12 border-b md:border-0 transition-colors duration-500 ${isCyberMode ? 'bg-slate-950/90 border-slate-800' : 'bg-gray-50/95 border-gray-200'}`}
        >
            <div 
                className="flex overflow-x-auto gap-2 no-scrollbar md:flex-wrap md:justify-center pb-2 md:pb-0"
                role="tablist"
                aria-label="工具分類"
            >
                {categories.map(cat => (
                    <div key={cat} role="presentation">
                        <button
                            role="tab"
                            aria-selected={activeCategory === cat}
                            aria-controls="tools-container"
                            className={`px-4 py-2 rounded-full text-sm font-medium transition-all duration-200 whitespace-nowrap flex-shrink-0
                                ${activeCategory === cat 
                                    ? 'bg-primary dark:bg-cyan-600 text-white shadow-md shadow-indigo-500/20 dark:shadow-cyan-500/40 transform scale-105' 
                                    : 'bg-white dark:bg-slate-800 text-muted dark:text-slate-400 hover:bg-gray-100 dark:hover:bg-slate-700 hover:text-text dark:hover:text-cyan-200 border border-gray-100 dark:border-slate-700'}`}
                            onClick={() => onCategoryChange(cat)}
                        >
                            {cat}
                            {cat !== "All" && (
                                <span className={`ml-2 text-xs ${activeCategory === cat ? 'opacity-75' : ''}`}>
                                    ({getToolsCount(cat)})
                                </span>
                            )}
                        </button>
                    </div>
                ))}
            </div>
        </nav>
    );
};

export default CategoryNav;