import { useState, useEffect, useCallback } from 'react';

const STORAGE_KEY = 'kencheng-bookmarks';
const RECENT_KEY = 'kencheng-recent';

export const useBookmarks = () => {
    const [bookmarks, setBookmarks] = useState(() => {
        try {
            const saved = localStorage.getItem(STORAGE_KEY);
            return saved ? JSON.parse(saved) : [];
        } catch { return []; }
    });

    const [recentlyUsed, setRecentlyUsed] = useState(() => {
        try {
            const saved = localStorage.getItem(RECENT_KEY);
            return saved ? JSON.parse(saved) : [];
        } catch { return []; }
    });

    useEffect(() => {
        try {
            localStorage.setItem(STORAGE_KEY, JSON.stringify(bookmarks));
        } catch {}
    }, [bookmarks]);

    useEffect(() => {
        try {
            localStorage.setItem(RECENT_KEY, JSON.stringify(recentlyUsed));
        } catch {}
    }, [recentlyUsed]);

    const toggleBookmark = useCallback((toolName) => {
        setBookmarks(prev => {
            if (prev.includes(toolName)) {
                return prev.filter(name => name !== toolName);
            }
            return [...prev, toolName];
        });
    }, []);

    const isBookmarked = useCallback((toolName) => {
        return bookmarks.includes(toolName);
    }, [bookmarks]);

    const addRecentUse = useCallback((tool) => {
        setRecentlyUsed(prev => {
            const filtered = prev.filter(t => t.name !== tool.name);
            const updated = [{ ...tool, lastUsed: Date.now() }, ...filtered].slice(0, 10);
            return updated;
        });
    }, []);

    const clearBookmarks = useCallback(() => {
        setBookmarks([]);
    }, []);

    const clearRecent = useCallback(() => {
        setRecentlyUsed([]);
    }, []);

    return {
        bookmarks,
        recentlyUsed,
        toggleBookmark,
        isBookmarked,
        addRecentUse,
        clearBookmarks,
        clearRecent
    };
};

export default useBookmarks;