import React, { useState } from 'react';
import ToolCard from './ToolCard.jsx';
import { LucideIcon } from './IconMap.jsx';

const CategorySection = ({ category, tools, subcategoryOrder, isCyber, onShowQR, isExpanded, onToggle, view, isBookmarked, onToggleBookmark, onVisit }) => {
    const isKenChengTDA = category === "Ken Cheng製作的TDA";
    const isListView = view === 'list';
    const [expandedSubcats, setExpandedSubcats] = useState(
        isKenChengTDA ? subcategoryOrder.reduce((acc, sub) => ({ ...acc, [sub]: true }), {}) : {}
    );

    const toggleSubcat = (subcat) => {
        setExpandedSubcats(prev => ({ ...prev, [subcat]: !prev[subcat] }));
    };

    const getSubcatIcon = (subCat) => {
        if (subCat === "教學TDA") return "BookOpen";
        if (subCat === "語文TDA") return "Languages";
        if (subCat === "數學TDA") return "Calculator";
        if (subCat === "電腦") return "Monitor";
        if (subCat === "科學") return "Atom";
        if (subCat === "實用工具") return "Wrench";
        return "Circle";
    };

    const gridClasses = isListView
        ? 'tool-card-list'
        : 'grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6';

    const renderToolCard = (tool, idx) => (
        <ToolCard
            key={`${tool.name}-${idx}`}
            tool={tool}
            onShowQR={onShowQR}
            view={view}
            isBookmarked={isBookmarked(tool.name)}
            onToggleBookmark={onToggleBookmark}
            onVisit={onVisit}
        />
    );

    return (
        <section
            className="animate-fade-in"
            aria-labelledby={`category-${category.replace(/\s+/g, '-')}`}
        >
            <button
                onClick={onToggle}
                className={`w-full flex items-center justify-between gap-4 mb-6 border-l-4 pl-4 transition-colors duration-500 cursor-pointer bg-transparent border-0 p-0 m-0 ${
                    isCyber ? 'border-cyan-500' : 'border-primary'
                }`}
                aria-expanded={isExpanded}
                aria-controls={`category-content-${category.replace(/\s+/g, '-')}`}
            >
                <div className="flex items-center gap-3">
                    <h2
                        id={`category-${category.replace(/\s+/g, '-')}`}
                        className={`text-2xl font-bold tracking-tight transition-colors duration-500 ${
                            isCyber ? 'text-cyan-50' : 'text-gray-800'
                        }`}
                    >
                        {category}
                    </h2>
                    <span
                        className={`text-xs font-semibold px-2.5 py-0.5 rounded-full transition-colors duration-500 ${
                            isCyber ? 'bg-slate-800 text-cyan-400' : 'bg-gray-100 text-gray-600'
                        }`}
                        aria-label={`共 ${tools.length} 個工具`}
                    >
                        {tools.length}
                    </span>
                </div>
                <LucideIcon
                    name={isExpanded ? "ChevronUp" : "ChevronDown"}
                    className={`w-6 h-6 transition-transform duration-300 ${isCyber ? 'text-cyan-400' : 'text-gray-500'}`}
                    aria-hidden="true"
                />
            </button>

            <div
                id={`category-content-${category.replace(/\s+/g, '-')}`}
                className={`category-content ${isExpanded ? 'expanded' : ''}`}
            >
                {isKenChengTDA ? (
                    <div className="space-y-8 pl-0 md:pl-4">
                        {subcategoryOrder.map(subCat => {
                            const subTools = tools.filter(t => t.subcategory === subCat);
                            if (subTools.length === 0) return null;

                            return (
                                <div key={subCat} className="space-y-4">
                                    <button
                                        onClick={() => toggleSubcat(subCat)}
                                        className={`w-full flex items-center gap-3 text-lg font-semibold border-b pb-2 transition-colors duration-500 cursor-pointer bg-transparent border-0 p-0 m-0 ${
                                            isCyber ? 'text-slate-300 border-slate-800' : 'text-gray-600 border-gray-100'
                                        }`}
                                        aria-expanded={expandedSubcats[subCat]}
                                        aria-controls={`subcat-content-${subCat}`}
                                    >
                                        <LucideIcon
                                            name={getSubcatIcon(subCat)}
                                            className={`w-5 h-5 transition-colors duration-500 ${isCyber ? 'text-fuchsia-400' : 'text-indigo-500'}`}
                                            aria-hidden="true"
                                        />
                                        {subCat}
                                        <span className={`text-xs font-medium px-2 py-0.5 rounded-full ml-2 ${
                                            isCyber ? 'bg-slate-800 text-slate-400' : 'bg-gray-100 text-gray-500'
                                        }`}>
                                            {subTools.length}
                                        </span>
                                        <LucideIcon
                                            name={expandedSubcats[subCat] ? "ChevronUp" : "ChevronDown"}
                                            className="w-4 h-4 ml-auto"
                                            aria-hidden="true"
                                        />
                                    </button>

                                    <div
                                        id={`subcat-content-${subCat}`}
                                        className={`subcategory-content ${expandedSubcats[subCat] ? 'expanded' : ''}`}
                                    >
                                        <div className={gridClasses}>
                                            {subTools.map((tool, idx) => renderToolCard(tool, idx))}
                                        </div>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                ) : (
                    <div className={gridClasses}>
                        {tools.map((tool, idx) => renderToolCard(tool, idx))}
                    </div>
                )}
            </div>
        </section>
    );
};

export default CategorySection;