import React, { useMemo } from 'react';
import { LucideIcon } from './IconMap.jsx';
import ToolCard from './ToolCard.jsx';

const Dashboard = ({ rawData, categoryPriority, isCyberMode, onShowQR, onToggleBookmark, isBookmarked, onVisit }) => {
    const stats = useMemo(() => {
        const totalTools = rawData.length;
        const categoryCount = {};
        rawData.forEach(tool => {
            categoryCount[tool.category] = (categoryCount[tool.category] || 0) + 1;
        });
        const sortedCategories = Object.entries(categoryCount)
            .sort((a, b) => {
                const idxA = categoryPriority.indexOf(a[0]);
                const idxB = categoryPriority.indexOf(b[0]);
                if (idxA !== -1 && idxB !== -1) return idxA - idxB;
                if (idxA !== -1) return -1;
                if (idxB !== -1) return 1;
                return b[1] - a[1];
            })
            .slice(0, 6);
        return { totalTools, categoryCount, sortedCategories };
    }, [rawData, categoryPriority]);

    const weeklyPicks = useMemo(() => {
        const shuffled = [...rawData].sort(() => Math.random() - 0.5);
        return shuffled.slice(0, 5);
    }, [rawData]);

    const maxCount = useMemo(() => {
        return Math.max(...stats.sortedCategories.map(([, count]) => count), 1);
    }, [stats.sortedCategories]);

    const getCategoryIcon = (category) => {
        if (category === "Ken Cheng製作的TDA") return "Wrench";
        if (category === "AI 助手") return "Bot";
        if (category === "開發工具 Vibe coding") return "Code2";
        if (category.includes("影片") || category.includes("動畫")) return "Video";
        if (category.includes("簡報")) return "Presentation";
        if (category.includes("科學")) return "Atom";
        return "Folder";
    };

    return (
        <div className="mb-12 space-y-10">
            <section>
                <h2 className={`text-xl font-bold mb-6 flex items-center gap-2 ${isCyberMode ? 'text-cyan-50' : 'text-gray-800'}`}>
                    <LucideIcon name="BarChart" className="w-6 h-6 text-primary dark:text-cyan-400" />
                    工具統計
                </h2>
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                    <div className={`p-5 rounded-xl border transition-colors ${isCyberMode ? 'bg-slate-900/50 border-cyan-500/30' : 'bg-white border-gray-100 shadow-sm'}`}>
                        <p className={`text-3xl font-bold ${isCyberMode ? 'text-cyan-400' : 'text-primary'}`}>{stats.totalTools}</p>
                        <p className={`text-sm ${isCyberMode ? 'text-slate-400' : 'text-muted'}`}>總工具數</p>
                    </div>
                    <div className={`p-5 rounded-xl border transition-colors ${isCyberMode ? 'bg-slate-900/50 border-cyan-500/30' : 'bg-white border-gray-100 shadow-sm'}`}>
                        <p className={`text-3xl font-bold ${isCyberMode ? 'text-fuchsia-400' : 'text-secondary'}`}>{Object.keys(stats.categoryCount).length}</p>
                        <p className={`text-sm ${isCyberMode ? 'text-slate-400' : 'text-muted'}`}>分類數量</p>
                    </div>
                    <div className={`p-5 rounded-xl border transition-colors ${isCyberMode ? 'bg-slate-900/50 border-cyan-500/30' : 'bg-white border-gray-100 shadow-sm'}`}>
                        <p className={`text-3xl font-bold ${isCyberMode ? 'text-green-400' : 'text-green-600'}`}>7</p>
                        <p className={`text-sm ${isCyberMode ? 'text-slate-400' : 'text-muted'}`}>子分類</p>
                    </div>
                    <div className={`p-5 rounded-xl border transition-colors ${isCyberMode ? 'bg-slate-900/50 border-cyan-500/30' : 'bg-white border-gray-100 shadow-sm'}`}>
                        <p className={`text-3xl font-bold ${isCyberMode ? 'text-yellow-400' : 'text-yellow-600'}`}>5</p>
                        <p className={`text-sm ${isCyberMode ? 'text-slate-400' : 'text-muted'}`}>精選工具</p>
                    </div>
                </div>
            </section>

            <section>
                <h2 className={`text-xl font-bold mb-6 flex items-center gap-2 ${isCyberMode ? 'text-cyan-50' : 'text-gray-800'}`}>
                    <LucideIcon name="Database" className="w-6 h-6 text-primary dark:text-cyan-400" />
                    分類分布
                </h2>
                <div className={`p-6 rounded-xl border transition-colors ${isCyberMode ? 'bg-slate-900/50 border-cyan-500/30' : 'bg-white border-gray-100 shadow-sm'}`}>
                    <div className="space-y-4">
                        {stats.sortedCategories.map(([category, count]) => {
                            const percentage = Math.round((count / maxCount) * 100);
                            const barColor = category === "Ken Cheng製作的TDA"
                                ? 'bg-primary'
                                : isCyberMode ? 'bg-cyan-500' : 'bg-indigo-400';
                            return (
                                <div key={category} className="space-y-2">
                                    <div className="flex justify-between text-sm">
                                        <span className={`flex items-center gap-2 ${isCyberMode ? 'text-slate-300' : 'text-gray-700'}`}>
                                            <LucideIcon name={getCategoryIcon(category)} className="w-4 h-4" />
                                            {category}
                                        </span>
                                        <span className={`font-medium ${isCyberMode ? 'text-cyan-400' : 'text-primary'}`}>{count}</span>
                                    </div>
                                    <div className={`h-2 rounded-full overflow-hidden ${isCyberMode ? 'bg-slate-800' : 'bg-gray-100'}`}>
                                        <div
                                            className={`h-full rounded-full transition-all duration-500 ${barColor}`}
                                            style={{ width: `${percentage}%` }}
                                        />
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            </section>

            <section>
                <h2 className={`text-xl font-bold mb-6 flex items-center gap-2 ${isCyberMode ? 'text-cyan-50' : 'text-gray-800'}`}>
                    <LucideIcon name="SparklesIcon" className="w-6 h-6 text-primary dark:text-cyan-400" />
                    每週精選
                </h2>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-4">
                    {weeklyPicks.map((tool, idx) => (
                        <div
                            key={`${tool.name}-${idx}`}
                            className="relative"
                        >
                            <div className={`absolute -top-1 -left-1 px-2 py-0.5 text-xs font-bold rounded-full ${isCyberMode ? 'bg-fuchsia-600 text-white' : 'bg-pink-500 text-white'}`}>
                                ★
                            </div>
                            <ToolCard
                                tool={tool}
                                onShowQR={onShowQR}
                                view="grid"
                                isBookmarked={isBookmarked(tool.name)}
                                onToggleBookmark={onToggleBookmark}
                                onVisit={onVisit}
                            />
                        </div>
                    ))}
                </div>
            </section>
        </div>
    );
};

export default Dashboard;