import { useEffect, useCallback } from 'react';

export const useKeyboardShortcuts = ({
    onToggleSearch,
    onToggleTheme,
    onToggleBookmarks,
    onToggleShortcutsHelp,
    searchInputRef
}) => {
    const handleKeyDown = useCallback((e) => {
        if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA') {
            if (e.key === 'Escape') {
                e.target.blur();
            }
            return;
        }

        switch (e.key) {
            case '/':
                e.preventDefault();
                if (searchInputRef?.current) {
                    searchInputRef.current.focus();
                }
                break;
            case 'b':
            case 'B':
                e.preventDefault();
                onToggleBookmarks?.();
                break;
            case 't':
            case 'T':
                e.preventDefault();
                onToggleTheme?.();
                break;
            case '?':
                e.preventDefault();
                onToggleShortcutsHelp?.();
                break;
            case 'Escape':
                onToggleShortcutsHelp?.(false);
                onToggleBookmarks?.(false);
                break;
            default:
                break;
        }
    }, [onToggleSearch, onToggleTheme, onToggleBookmarks, onToggleShortcutsHelp, searchInputRef]);

    useEffect(() => {
        document.addEventListener('keydown', handleKeyDown);
        return () => document.removeEventListener('keydown', handleKeyDown);
    }, [handleKeyDown]);
};

export const keyboardShortcuts = [
    { key: '/', description: '聚焦搜尋框' },
    { key: 'B', description: '切換書籤側邊欄' },
    { key: 'T', description: '切換主題' },
    { key: '?', description: '顯示快捷鍵說明' },
    { key: 'Esc', description: '關閉彈窗' }
];

export default useKeyboardShortcuts;