import React, { useState, useEffect, useRef } from 'react';
import QRCode from 'qrcode';
import { LucideIcon } from './IconMap.jsx';

const QRCodeModal = ({ url, title, onClose }) => {
    const [imgSrc, setImgSrc] = useState("");
    const modalRef = useRef(null);
    const closeButtonRef = useRef(null);

    useEffect(() => {
        if (url) {
            QRCode.toDataURL(url, {
                width: 300,
                margin: 2,
                color: {
                    dark: '#0f172a',
                    light: '#ffffff'
                }
            }, (err, dataUrl) => {
                if (!err) setImgSrc(dataUrl);
            });
        }
    }, [url]);

    useEffect(() => {
        if (closeButtonRef.current) {
            closeButtonRef.current.focus();
        }
        const handleEscape = (e) => {
            if (e.key === 'Escape') onClose();
        };
        document.addEventListener('keydown', handleEscape);
        return () => document.removeEventListener('keydown', handleEscape);
    }, [onClose]);

    return (
        <div 
            className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fade-in" 
            onClick={onClose}
            role="dialog"
            aria-modal="true"
            aria-labelledby="qr-modal-title"
        >
            <div 
                ref={modalRef}
                className="bg-white dark:bg-slate-900 rounded-2xl shadow-2xl max-w-sm w-full p-6 relative animate-scale-in border dark:border-cyan-500/30" 
                onClick={e => e.stopPropagation()}
            >
                <button 
                    ref={closeButtonRef}
                    onClick={onClose} 
                    className="absolute top-4 right-4 text-gray-400 hover:text-gray-600 dark:hover:text-cyan-400 hover:bg-gray-100 dark:hover:bg-slate-800 p-1 rounded-full transition-colors"
                    aria-label="關閉 QR Code 視窗"
                >
                    <LucideIcon name="X" className="w-5 h-5" />
                </button>
                
                <div className="text-center mb-6">
                    <h3 id="qr-modal-title" className="text-xl font-bold text-gray-800 dark:text-cyan-50 mb-2">{title}</h3>
                    <p className="text-sm text-gray-500 dark:text-slate-400 break-all px-2" aria-label={`網址：${url}`}>{url}</p>
                </div>

                <div className="flex justify-center mb-6">
                    {imgSrc ? (
                        <div className="p-3 border border-gray-100 dark:border-slate-700 rounded-xl shadow-sm bg-white">
                            <img src={imgSrc} alt={`${title} 的 QR Code`} className="w-48 h-48 md:w-56 md:h-56" />
                        </div>
                    ) : (
                        <div className="w-48 h-48 flex items-center justify-center bg-gray-50 dark:bg-slate-800 rounded-xl" role="status" aria-label="QR Code 生成中">
                            <span className="text-gray-400 dark:text-slate-500 text-sm">生成中...</span>
                        </div>
                    )}
                </div>

                <div className="flex gap-3">
                    <a 
                        href={imgSrc} 
                        download={`${title}-qrcode.png`}
                        className={`flex-1 flex items-center justify-center gap-2 py-3 bg-primary dark:bg-cyan-600 text-white font-medium rounded-xl shadow-lg shadow-indigo-500/30 dark:shadow-cyan-500/30 hover:bg-indigo-700 dark:hover:bg-cyan-500 transition-all ${!imgSrc ? 'opacity-50 pointer-events-none' : ''}`}
                        aria-label={`下載 ${title} 的 QR Code`}
                    >
                        <LucideIcon name="Download" className="w-4 h-4" aria-hidden="true" />
                        下載 PNG
                    </a>
                </div>
            </div>
        </div>
    );
};

export default QRCodeModal;