import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';

const STORAGE_KEY = 'kencheng-theme';

const themes = ['light', 'dark', 'cyber'];

const ThemeContext = createContext({
    theme: 'light',
    setTheme: () => {},
    toggleTheme: () => {}
});

export const useTheme = () => useContext(ThemeContext);

export const ThemeProvider = ({ children }) => {
    const [theme, setThemeState] = useState(() => {
        try {
            const saved = localStorage.getItem(STORAGE_KEY);
            return saved && themes.includes(saved) ? saved : 'light';
        } catch { return 'light'; }
    });

    useEffect(() => {
        try {
            localStorage.setItem(STORAGE_KEY, theme);
        } catch {}
    }, [theme]);

    useEffect(() => {
        document.documentElement.classList.remove('light', 'dark', 'cyber');
        if (theme === 'dark' || theme === 'cyber') {
            document.documentElement.classList.add('dark');
        }
        document.documentElement.classList.add(theme);
    }, [theme]);

    const setTheme = useCallback((newTheme) => {
        if (themes.includes(newTheme)) {
            setThemeState(newTheme);
        }
    }, []);

    const toggleTheme = useCallback(() => {
        setThemeState(prev => {
            const idx = themes.indexOf(prev);
            return themes[(idx + 1) % themes.length];
        });
    }, []);

    const cycleToNext = useCallback(() => {
        setThemeState(prev => {
            const idx = themes.indexOf(prev);
            return themes[(idx + 1) % themes.length];
        });
    }, []);

    return (
        <ThemeContext.Provider value={{ theme, setTheme, toggleTheme, cycleToNext, themes }}>
            {children}
        </ThemeContext.Provider>
    );
};

export default ThemeContext;