import React from 'react';
import { LucideIcon } from './IconMap.jsx';

const ViewToggle = ({ view, onViewChange }) => (
    <div className="flex items-center gap-2 mb-6 justify-end" role="group" aria-label="檢視模式">
        <span className={`text-sm ${view === 'grid' ? 'text-primary dark:text-cyan-400' : 'text-muted'}`}>
            <LucideIcon name="Grid" className="w-4 h-4 inline-block" />
        </span>
        <button
            onClick={() => onViewChange('grid')}
            className={`p-2 rounded-lg transition-all ${view === 'grid' ? 'bg-primary/10 text-primary dark:bg-cyan-600/20 dark:text-cyan-400' : 'text-muted hover:bg-gray-100 dark:hover:bg-slate-800'}`}
            aria-label="網格檢視"
            aria-pressed={view === 'grid'}
        >
            <LucideIcon name="Grid" className="w-4 h-4" />
        </button>
        <button
            onClick={() => onViewChange('list')}
            className={`p-2 rounded-lg transition-all ${view === 'list' ? 'bg-primary/10 text-primary dark:bg-cyan-600/20 dark:text-cyan-400' : 'text-muted hover:bg-gray-100 dark:hover:bg-slate-800'}`}
            aria-label="列表檢視"
            aria-pressed={view === 'list'}
        >
            <LucideIcon name="List" className="w-4 h-4" />
        </button>
        <span className={`text-sm ${view === 'list' ? 'text-primary dark:text-cyan-400' : 'text-muted'}`}>
            <LucideIcon name="List" className="w-4 h-4 inline-block" />
        </span>
    </div>
);

export default ViewToggle;