import React from 'react';
import { LucideIcon } from './IconMap.jsx';

const BookmarksSidebar = ({ isOpen, onClose, bookmarks, recentlyUsed, onToggleBookmark, isBookmarked, onVisit, isCyberMode }) => {
    if (!isOpen) return null;

    const formatTime = (timestamp) => {
        const diff = Date.now() - timestamp;
        const minutes = Math.floor(diff / 60000);
        const hours = Math.floor(diff / 3600000);
        const days = Math.floor(diff / 86400000);

        if (minutes < 1) return '剛剛';
        if (minutes < 60) return `${minutes} 分鐘前`;
        if (hours < 24) return `${hours} 小時前`;
        return `${days} 天前`;
    };

    return (
        <div className="fixed inset-0 z-[150] flex">
            <div
                className="absolute inset-0 bg-black/50 backdrop-blur-sm"
                onClick={onClose}
            />
            <div className="relative ml-auto w-full max-w-md h-full bg-white dark:bg-slate-900 shadow-2xl animate-fade-in overflow-y-auto">
                <div className="sticky top-0 bg-white dark:bg-slate-900 border-b border-gray-200 dark:border-slate-800 p-4 flex items-center justify-between z-10">
                    <h2 className="text-lg font-bold text-gray-800 dark:text-cyan-50 flex items-center gap-2">
                        <LucideIcon name="Heart" className="w-5 h-5 text-red-500 fill-current" />
                        我的收藏
                    </h2>
                    <button
                        onClick={onClose}
                        className="p-2 text-gray-400 hover:text-gray-600 dark:hover:text-cyan-400 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-lg transition-colors"
                        aria-label="關閉書籤側邊欄"
                    >
                        <LucideIcon name="X" className="w-5 h-5" />
                    </button>
                </div>

                <div className="p-4 space-y-6">
                    {bookmarks.length > 0 && (
                        <section>
                            <h3 className="text-sm font-semibold text-gray-500 dark:text-slate-400 uppercase tracking-wide mb-3">
                                已收藏 ({bookmarks.length})
                            </h3>
                            <div className="space-y-2">
                                {bookmarks.map((toolName) => {
                                    const tool = recentlyUsed.find(t => t.name === toolName) || { name: toolName, url: '#', icon: 'Link', desc: '' };
                                    return (
                                        <div
                                            key={toolName}
                                            className="flex items-center gap-3 p-3 bg-gray-50 dark:bg-slate-800/50 rounded-lg hover:bg-gray-100 dark:hover:bg-slate-800 transition-colors"
                                        >
                                            <LucideIcon name={tool.icon || 'Link'} className="w-5 h-5 text-primary dark:text-cyan-400 flex-shrink-0" />
                                            <div className="flex-grow min-w-0">
                                                <p className="font-medium text-gray-800 dark:text-cyan-50 truncate">{toolName}</p>
                                                <p className="text-xs text-gray-500 dark:text-slate-500 truncate">{tool.desc}</p>
                                            </div>
                                            <button
                                                onClick={() => onToggleBookmark(tool)}
                                                className="p-1.5 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors"
                                                title="移除書籤"
                                            >
                                                <LucideIcon name="Heart" className="w-4 h-4 fill-current" />
                                            </button>
                                        </div>
                                    );
                                })}
                            </div>
                        </section>
                    )}

                    {recentlyUsed.length > 0 && (
                        <section>
                            <h3 className="text-sm font-semibold text-gray-500 dark:text-slate-400 uppercase tracking-wide mb-3">
                                最近使用
                            </h3>
                            <div className="space-y-2">
                                {recentlyUsed.slice(0, 5).map((tool, idx) => (
                                    <a
                                        key={`${tool.name}-${idx}`}
                                        href={tool.url}
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        onClick={() => onVisit?.(tool)}
                                        className="flex items-center gap-3 p-3 bg-gray-50 dark:bg-slate-800/50 rounded-lg hover:bg-gray-100 dark:hover:bg-slate-800 transition-colors group"
                                    >
                                        <LucideIcon name={tool.icon || 'Link'} className="w-5 h-5 text-primary dark:text-cyan-400 flex-shrink-0" />
                                        <div className="flex-grow min-w-0">
                                            <p className="font-medium text-gray-800 dark:text-cyan-50 truncate group-hover:text-primary dark:group-hover:text-cyan-400">
                                                {tool.name}
                                            </p>
                                            <p className="text-xs text-gray-500 dark:text-slate-500">{formatTime(tool.lastUsed)}</p>
                                        </div>
                                        <LucideIcon name="ExternalLink" className="w-4 h-4 text-gray-400 group-hover:text-primary dark:group-hover:text-cyan-400" />
                                    </a>
                                ))}
                            </div>
                        </section>
                    )}

                    {bookmarks.length === 0 && recentlyUsed.length === 0 && (
                        <div className="text-center py-12">
                            <div className="p-4 bg-gray-50 dark:bg-slate-800/50 rounded-full inline-block mb-4">
                                <LucideIcon name="Heart" className="w-8 h-8 text-gray-300 dark:text-slate-600" />
                            </div>
                            <p className="text-gray-500 dark:text-slate-400">尚無收藏或使用記錄</p>
                            <p className="text-sm text-gray-400 dark:text-slate-500 mt-1">點擊工具的愛心按鈕即可收藏</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default BookmarksSidebar;