import React from 'react';
import { LucideIcon } from './IconMap.jsx';

const ShortcutsHelpModal = ({ isOpen, onClose }) => {
    const shortcuts = [
        { key: '/', description: '聚焦搜尋框' },
        { key: 'B', description: '切換書籤側邊欄' },
        { key: 'T', description: '切換主題' },
        { key: '?', description: '顯示快捷鍵說明' },
        { key: 'Esc', description: '關閉彈窗' }
    ];

    if (!isOpen) return null;

    return (
        <div
            className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fade-in"
            onClick={onClose}
            role="dialog"
            aria-modal="true"
            aria-labelledby="shortcuts-modal-title"
        >
            <div
                className="bg-white dark:bg-slate-900 rounded-2xl shadow-2xl max-w-md w-full p-6 relative animate-scale-in border dark:border-cyan-500/30"
                onClick={e => e.stopPropagation()}
            >
                <button
                    onClick={onClose}
                    className="absolute top-4 right-4 text-gray-400 hover:text-gray-600 dark:hover:text-cyan-400 hover:bg-gray-100 dark:hover:bg-slate-800 p-1 rounded-full transition-colors"
                    aria-label="關閉"
                >
                    <LucideIcon name="X" className="w-5 h-5" />
                </button>

                <h2 id="shortcuts-modal-title" className="text-xl font-bold text-gray-800 dark:text-cyan-50 mb-6 flex items-center gap-2">
                    <LucideIcon name="Keyboard" className="w-6 h-6 text-primary dark:text-cyan-400" />
                    鍵盤快捷鍵
                </h2>

                <div className="space-y-3">
                    {shortcuts.map(({ key, description }) => (
                        <div key={key} className="flex items-center justify-between py-2 border-b border-gray-100 dark:border-slate-800 last:border-0">
                            <span className="text-gray-600 dark:text-slate-300">{description}</span>
                            <kbd className="px-3 py-1.5 bg-gray-100 dark:bg-slate-800 text-gray-700 dark:text-cyan-300 text-sm font-mono rounded-lg border border-gray-200 dark:border-slate-700 shadow-sm">
                                {key}
                            </kbd>
                        </div>
                    ))}
                </div>

                <p className="mt-6 text-sm text-gray-500 dark:text-slate-500 text-center">
                    按 <kbd className="px-1.5 py-0.5 bg-gray-100 dark:bg-slate-800 text-xs font-mono rounded">?</kbd> 可隨時喚出此說明
                </p>
            </div>
        </div>
    );
};

export default ShortcutsHelpModal;