import React from 'react';
import { LucideIcon } from './IconMap.jsx';

const ThemeSelector = ({ theme, onThemeChange }) => {
    const themeOptions = [
        {
            id: 'light',
            label: '淺色',
            icon: 'Sun',
            colors: 'from-amber-400 to-orange-500',
            active: theme === 'light'
        },
        {
            id: 'dark',
            label: '深色',
            icon: 'Moon',
            colors: 'from-slate-600 to-slate-800',
            active: theme === 'dark'
        },
        {
            id: 'cyber',
            label: '夜視',
            icon: 'Sparkles',
            colors: 'from-cyan-500 to-fuchsia-600',
            active: theme === 'cyber'
        }
    ];

    return (
        <div className="fixed top-4 right-4 z-50 flex items-center gap-1 p-1.5 bg-white/90 dark:bg-slate-900/90 backdrop-blur-md border border-gray-200 dark:border-cyan-500/30 rounded-full shadow-lg">
            {themeOptions.map(({ id, label, icon, colors, active }) => (
                <button
                    key={id}
                    onClick={() => onThemeChange(id)}
                    className={`relative p-2 rounded-full transition-all duration-300 group ${
                        active
                            ? 'bg-gradient-to-br shadow-md'
                            : 'hover:bg-gray-100 dark:hover:bg-slate-800'
                    }`}
                    aria-label={`切換到${label}主題`}
                    aria-pressed={active}
                    title={label}
                >
                    {active && (
                        <div className={`absolute inset-0 bg-gradient-to-br ${colors} rounded-full opacity-90`} />
                    )}
                    <span className={`relative z-10 ${active ? 'text-white' : 'text-gray-600 dark:text-slate-400 group-hover:text-gray-800 dark:group-hover:text-slate-200'}`}>
                        <LucideIcon name={icon} className="w-4 h-4" />
                    </span>
                </button>
            ))}
        </div>
    );
};

export default ThemeSelector;